createSegmentGroup(
  redirectTo: string,
  group: UrlSegmentGroup,
  segments: UrlSegment[],
  posParams: {[k: string]: UrlSegment},
): UrlSegmentGroup {
  const updatedSegments = this.createSegments(redirectTo, group.segments, segments, posParams);

  let children: {[n: string]: UrlSegmentGroup} = {};
  Object.entries(group.children).forEach(([name, child]) => {
    children[name] = this.createSegmentGroup(redirectTo, child, segments, posParams);
  });

  return new UrlSegmentGroup(updatedSegments, children);
}

stopMonitoring(element: HTMLElement | ElementRef<HTMLElement>): void {
  const nativeElement = coerceElement(element);
  const elementInfo = this._elementInfo.get(nativeElement);

  if (elementInfo) {
    elementInfo.subject.complete();

    this._setClasses(nativeElement);
    this._elementInfo.delete(nativeElement);
    this._removeGlobalListeners(elementInfo);
  }
}

add(): () => void {
  const taskId = this.internalPendingTasks.add();
  return () => {
    if (!this.internalPendingTasks.has(taskId)) {
      // This pending task has already been cleared.
      return;
    }
    // Notifying the scheduler will hold application stability open until the next tick.
    this.scheduler.notify(NotificationSource.PendingTaskRemoved);
    this.internalPendingTasks.remove(taskId);
  };
}

